// Build Scout Queries per site — aligned to domain profiles
const SITE_PROFILES = {
  sinabarimd: {
    role: 'Canonical identity hub — biography, current work, entity clarity',
    allowed_topics: 'bio, current work, media, selected writing, entity',
    forbidden_topics: 'thin blog spam, clinic impersonation',
    queries: [
      '"Sina Bari" OR "Dr. Sina Bari" news 2026',
      'physician executive personal brand search visibility',
      'healthcare AI leader profile search results',
    ]
  },
  sinabari_net: {
    role: 'Health technology authority (75% AI, 25% broader medtech)',
    allowed_topics: 'healthcare AI, clinical AI, surgical robotics, digital health, medical devices, EHR innovation, precision medicine, telemedicine, wearable health tech, pharma technology, health data interoperability, genomics, clinical decision support',
    forbidden_topics: 'plastic surgery, aesthetics, generic consumer AI, cryptocurrency',
    queries: [
      'healthcare AI clinical workflow automation news 2026',
      'medical technology innovation digital health breakthroughs this week',
      'FDA AI medical device surgical robotics approval 2026',
      'precision medicine health data interoperability EHR update 2026',
    ]
  },
  drsinabari: {
    role: 'Editorial node — essays, interviews, long-form commentary',
    allowed_topics: 'essays, interviews, commentary, long-form narrative',
    forbidden_topics: 'clinic marketing, generic AI news',
    queries: [
      'medicine technology ethics commentary 2026',
      'physician writer opinion AI healthcare current debate',
      'doctor perspective technology society essay topics',
    ]
  },
  sinabariplasticsurgery: {
    role: 'Legacy specialty — aesthetics education, aging, rejuvenation',
    allowed_topics: 'aesthetics education, aging, rejuvenation, surgery',
    forbidden_topics: 'healthcare AI, enterprise tech',
    queries: [
      'plastic surgery innovation patient safety 2026',
      'facial rejuvenation new technique research',
      'aesthetic medicine trends surgeon education',
    ]
  },
};

const sites = Object.keys(SITE_PROFILES);
return sites.map(site_id => ({
  json: {
    site_id,
    phase: 'scout',
    profile: SITE_PROFILES[site_id],
    queries: SITE_PROFILES[site_id].queries,
  }
}));

// Expand queries into individual items for HTTP Request node
const staticData = $getWorkflowStaticData('global');
const TAVILY_API_KEY = staticData.tavily_key;
if (!TAVILY_API_KEY) throw new Error('tavily_key not set in staticData.global');

const { site_id, queries, profile } = $json;

return queries.map(query => ({
  json: {
    site_id,
    profile,
    query,
    tavily_body: JSON.stringify({
      api_key: TAVILY_API_KEY,
      query,
      search_depth: 'advanced',
      max_results: 5,
      include_answer: true,
      include_raw_content: false,
    }),
  }
}));

// Build Phase 1 prompt — topic synthesis aligned to domain profile
const { site_id, profile, search_results } = $json;

const resultsText = (search_results || []).map(sr => {
  const items = (sr.results || []).map(r =>
    `  TITLE: ${r.title}\n  URL: ${r.url}\n  CONTENT: ${r.content || ''}\n  DATE: ${r.published_date || 'unknown'}`
  ).join('\n---\n');
  return `QUERY: ${sr.query}\nANSWER: ${sr.answer || 'N/A'}\nRESULTS:\n${items}`;
}).join('\n===\n');

const prompt = `You are the Content Research Agent (Phase 1: Topic Scout).
Site: ${site_id} — Role: ${profile.role}
Allowed topics: ${profile.allowed_topics}
Forbidden topics: ${profile.forbidden_topics}

Based on the search results below, suggest 2-3 candidate content topics.
For each candidate, output a JSON object with:
- recommended_topic: one sentence describing the topic and angle
- rationale: 1-2 sentences on why this is worth writing now
- timeliness: how fresh this is (days/weeks)
- confidence: "high" | "medium" | "low"
- content_type: "short_form" | "standard" | "longform"
- novel_angle: the one non-obvious insight that makes this worth reading
- aeo_questions: array of 3-5 specific questions the content should answer
- citable_sources: array of {title, url, publication, date, key_fact}

Output a JSON array only. No markdown, no commentary.
Only suggest topics within allowed_topics. Never suggest forbidden_topics.

SEARCH RESULTS:
${resultsText}`;

return [{
  json: {
    ...($json),
    openclaw_request_body: JSON.stringify({ model: 'openclaw', input: prompt }),
    openclawAgentId: 'researcher-scout',
  }
}];

// Extract candidate topics from OpenClaw response
// Re-attach upstream context lost after HTTP Request node
const upstream = $('Build Phase1 OpenClaw Request').first().json;
const output = $json.output || [];
let text = '';
for (const block of output) {
  for (const part of (block.content || [])) {
    if (part.text) text += part.text;
  }
}

text = text.replace(/^```json\s*/m, '').replace(/^```\s*$/m, '').trim();

let candidates;
try {
  candidates = JSON.parse(text);
  if (!Array.isArray(candidates)) candidates = [candidates];
} catch(e) {
  const match = text.match(/\[[\s\S]*\]/);
  if (match) {
    try { candidates = JSON.parse(match[0]); }
    catch(e2) { candidates = [{ error: 'Parse failed: ' + text.slice(0, 200) }]; }
  } else {
    candidates = [{ error: 'No JSON array found: ' + text.slice(0, 200) }];
  }
}

return [{ json: { ...upstream, candidates } }];

// Store candidates in static data — operator must review before Phase 2 runs
const staticData = $getWorkflowStaticData('global');
const { site_id, candidates } = $json;

if (!staticData.candidates) staticData.candidates = {};

staticData.candidates[site_id] = {
  generated_at: new Date().toISOString(),
  site_id,
  source: 'scout',
  items: candidates,
};

return [{ json: {
  stored: true,
  site_id,
  candidate_count: candidates.length,
  generated_at: staticData.candidates[site_id].generated_at,
} }];

const items = $input.all();
const summary = items.map(i => ({
  site_id: i.json.site_id,
  candidate_count: i.json.candidate_count,
  stored: i.json.stored,
}));
return [{ json: {
  phase: 'scout_complete',
  summary,
  review_url: 'GET https://n8n.sinabarimd.com/webhook/list-research-candidates',
  next_step: 'Review candidates, then POST to /webhook/research-deep to approve a topic',
} }];

// Return all stored candidates for operator review
const staticData = $getWorkflowStaticData('global');
const candidates = staticData.candidates || {};

return [{ json: {
  generated_at: new Date().toISOString(),
  instructions: {
    review: 'Below are the current research candidates per site.',
    approve: 'POST to /webhook/research-deep with: { site_id, selected_topic, content_type, additional_direction }',
    add_custom: 'POST to /webhook/add-research-topic with: { site_id, topic, content_type }',
    skip: 'POST to /webhook/research-deep with: { site_id, selected_topic: "any", skip_this_week: true }',
  },
  sites: candidates,
} }];

// Add operator-authored topic to candidate list
const staticData = $getWorkflowStaticData('global');
const body = $json;
const { site_id, topic, content_type = 'standard', attachment_text = null } = body;

if (!site_id || !topic) {
  return [{ json: { success: false, error: 'Required: site_id, topic' } }];
}

if (!staticData.candidates) staticData.candidates = {};
if (!staticData.candidates[site_id]) {
  staticData.candidates[site_id] = {
    generated_at: new Date().toISOString(),
    site_id,
    source: 'operator',
    items: [],
  };
}

const customCandidate = {
  recommended_topic: topic,
  content_type,
  confidence: 'operator',
  source: 'operator_added',
  added_at: new Date().toISOString(),
  rationale: 'Operator-specified topic',
  novel_angle: '(to be determined by deep research)',
  aeo_questions: [],
  citable_sources: [],
};

if (attachment_text) {
  customCandidate.attachment_text = attachment_text.slice(0, 30000);
  customCandidate.has_attachment = true;
}

staticData.candidates[site_id].items.push(customCandidate);

return [{ json: {
  success: true,
  site_id,
  added_topic: topic,
  has_attachment: !!attachment_text,
  total_candidates: staticData.candidates[site_id].items.length,
} }];

// Expand approved topic into targeted Tavily query set
const body = $json.body || $json;
const { site_id, selected_topic, content_type = 'standard', additional_direction = '', skip_this_week = false } = body;

if (!site_id || !selected_topic) {
  throw new Error('Required: site_id and selected_topic');
}

if (skip_this_week) {
  return [{ json: { skipped: true, site_id } }];
}

const baseQueries = [
  `${selected_topic} latest research 2026`,
  `${selected_topic} expert opinion analysis`,
  `${selected_topic} statistics data evidence`,
  `${selected_topic} controversies challenges criticism`,
];

const longformQueries = content_type === 'longform' ? [
  `${selected_topic} broader implications healthcare medicine`,
  `${selected_topic} history context background`,
  `${selected_topic} future predictions trends`,
  `related topics ${selected_topic} connections`,
] : [];

const siteAngleQueries = {
  sinabarimd:             [`Dr Sina Bari ${selected_topic}`, `physician executive ${selected_topic} perspective`],
  sinabari_net:           [`clinical implementation ${selected_topic}`, `hospital ${selected_topic} case study`],
  drsinabari:             [`physician commentary ${selected_topic}`, `medical ethics ${selected_topic}`],
  sinabariplasticsurgery: [`surgical application ${selected_topic}`, `patient outcomes ${selected_topic}`],
};

return [{
  json: {
    site_id, selected_topic, content_type, additional_direction,
    is_longform: content_type === 'longform',
    queries: [...baseQueries, ...longformQueries, ...(siteAngleQueries[site_id] || [])],
    phase: 'deep_research',
  }
}];

// Clear candidates for skipped site
const staticData = $getWorkflowStaticData('global');
const { site_id } = $json;
if (staticData.candidates) delete staticData.candidates[site_id];
return [{ json: { status: 'skipped', site_id, candidates_cleared: true } }];

// Queue the research — the HTTP node after this fires the API
const upstream = $('Plan Deep Research Queries').first().json;
const { site_id, selected_topic, content_type } = upstream;

// Look up attachment_text from the candidate in staticData
const staticData = $getWorkflowStaticData('global');
let attachment_text = '';
if (staticData.candidates && staticData.candidates[site_id]) {
  const items = staticData.candidates[site_id].items || [];
  const searchStr = selected_topic.toLowerCase().slice(0, 30);
  const match = items.find(i =>
    (i.recommended_topic || i.topic || '').toLowerCase().includes(searchStr)
  );
  if (match && match.attachment_text) {
    attachment_text = match.attachment_text;
  }
}

// NOTE: Do NOT clear candidates here — cleared only after brief successfully stores

const apiBody = { query: selected_topic, site_id, content_type, selected_topic };
if (attachment_text) apiBody.attachment_context = attachment_text;

return [{ json: {
  ...upstream,
  attachment_text,
  research_api_body: JSON.stringify(apiBody),
} }];

// Research is queued — return immediately
const upstream = $('Plan Deep Research Queries').first().json;
return [{ json: { 
  status: 'queued',
  site_id: upstream.site_id,
  selected_topic: upstream.selected_topic,
  message: 'Academic research queued. Draft will appear in Drafts tab within 5-10 minutes.',
} }];

// Extract research brief JSON from OpenClaw response
const output = $json.output || [];
let text = '';
for (const block of output) {
  for (const part of (block.content || [])) {
    if (part.text) text += part.text;
  }
}

text = text.replace(/^```json\s*/m, '').replace(/^```\s*$/m, '').trim();

let brief;
try {
  brief = JSON.parse(text);
} catch(e) {
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try { brief = JSON.parse(match[0]); }
    catch(e2) { throw new Error('Could not parse brief: ' + text.slice(0, 300)); }
  } else {
    throw new Error('No JSON object found in response: ' + text.slice(0, 300));
  }
}

brief.consumed = false;
brief.queued_at = new Date().toISOString();

return [{ json: { ...($json), brief } }];

// Clear the researched topic from candidates
const staticData = $getWorkflowStaticData('global');
const upstream = $('Plan Deep Research Queries').first().json;
const site_id = upstream.site_id || $json.site_id;
const selected_topic = upstream.selected_topic || '';

if (staticData.candidates && staticData.candidates[site_id]) {
  const items = staticData.candidates[site_id].items || staticData.candidates[site_id].candidates || [];
  // Remove the specific topic that was researched (fuzzy match on first 30 chars)
  const searchStr = selected_topic.toLowerCase().slice(0, 30);
  const remaining = items.filter(item => {
    const topic = (item.recommended_topic || item.topic || '').toLowerCase();
    return !topic.includes(searchStr);
  });

  if (staticData.candidates[site_id].items) {
    staticData.candidates[site_id].items = remaining;
  } else if (staticData.candidates[site_id].candidates) {
    staticData.candidates[site_id].candidates = remaining;
  }
}

return [{ json: { ...($json), candidates_cleared: true, site_id } }];

// Build a research brief from academic paper results + OpenClaw synthesis
const body = $json.body || $json;
const { site_id, selected_topic, content_type, citable_sources, papers_found, report_excerpt } = body;

// --- Pass 1: Structure the raw data ---
const sourceSummaries = (citable_sources || []).slice(0, 10).map((s, i) =>
  `[${i+1}] ${s.title} (${s.publication || 'unknown'}, ${s.date || 'n/d'})\n    Key fact: ${s.key_fact || 'N/A'}`
).join('\n');

// --- Pass 2: OpenClaw synthesis for richer brief ---
const synthesisPrompt = `You are a research analyst preparing a content brief for a physician-authored article.

Topic: ${selected_topic}
Site: ${site_id}
Content type: ${content_type || 'standard'}

ACADEMIC SOURCES FOUND (${papers_found || 0} papers):
${sourceSummaries}

RESEARCH REPORT EXCERPT:
${(report_excerpt || '').slice(0, 3000)}

Based on these sources, produce a structured research brief as a JSON object with these fields:
- recommended_topic: refined one-sentence topic with the strongest angle from the evidence
- novel_angle: the single most surprising or non-obvious finding from the papers
- key_findings: array of 5-8 specific, quantitative findings (cite the source paper)
- interconnections: array of 2-3 connections between findings that create a narrative
- aeo_questions: array of 5 specific questions this article should answer (real patient/reader questions)
- suggested_structure: 2-3 sentence outline of how to organize the article
- confidence: "high" if 10+ relevant papers, "medium" if 5-10, "low" if <5
- writing_hooks: array of 2-3 compelling opening lines or angles

Output JSON only. No markdown fences, no commentary.`;

let brief;
try {
  const openclawResp = await $http.request({
    method: 'POST',
    url: 'http://host.docker.internal:18789/v1/responses',
    headers: {
      'Authorization': 'Bearer YOUR_OPENCLAW_KEY',
      'Content-Type': 'application/json',
      'x-openclaw-agent-id': 'researcher-synthesis',
    },
    body: { model: 'openclaw', input: synthesisPrompt },
  });

  let text = '';
  for (const block of (openclawResp.output || [])) {
    for (const part of (block.content || [])) {
      if (part.text) text += part.text;
    }
  }
  text = text.replace(/^```json\s*/m, '').replace(/^```\s*$/m, '').trim();

  try {
    brief = JSON.parse(text);
  } catch(e) {
    const match = text.match(/\{[\s\S]*\}/);
    if (match) brief = JSON.parse(match[0]);
    else throw e;
  }
} catch(e) {
  // Fallback: build brief without synthesis (original behavior)
  brief = {
    recommended_topic: selected_topic,
    novel_angle: report_excerpt ? report_excerpt.split('.').slice(0, 2).join('.') + '.' : 'Based on academic literature review',
    key_findings: (citable_sources || []).slice(0, 5).map(s => s.key_fact || s.title),
    aeo_questions: [],
    suggested_structure: '',
    confidence: papers_found > 20 ? 'high' : papers_found > 5 ? 'medium' : 'low',
  };
}

// Always attach metadata
brief.site_id = site_id;
brief.research_date = new Date().toISOString().split('T')[0];
brief.content_type = content_type || 'standard';
brief.citable_sources = citable_sources || [];
brief.papers_found = papers_found;
brief.consumed = false;

// Clear consumed candidates
const staticData = $getWorkflowStaticData('global');
if (staticData.candidates && staticData.candidates[site_id]) {
  const items = staticData.candidates[site_id].items || [];
  const searchStr = selected_topic.toLowerCase().slice(0, 30);
  staticData.candidates[site_id].items = items.filter(i => 
    !(i.recommended_topic || i.topic || '').toLowerCase().includes(searchStr)
  );
}

return [{ json: { brief, site_id, selected_topic } }];

// Fire content generation — don't wait for it to complete
const brief = $('Build Brief from Papers').first().json.brief;

// Fire and forget with a short timeout — we don't need the response
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://n8n.sinabarimd.com/webhook/content-generate',
    headers: { 'Content-Type': 'application/json' },
    body: { site_id: brief.site_id, research_brief: brief },
    json: true,
    timeout: 10000,  // Short timeout — we just need to fire it
  });
  return [{ json: { success: true, message: 'Draft generation triggered' } }];
} catch (e) {
  // Timeout is expected — content generation takes minutes
  // The important thing is the request was sent
  return [{ json: { success: true, message: 'Draft generation triggered (async)', note: String(e.message || '').slice(0, 50) } }];
}

const input = $input.first().json.body;
const site_id = input.site_id || 'sinabarimd';
const content_type = input.content_type || 'standard';
const seed_text = (input.seed_text || '').trim();

// Get existing candidates to avoid duplication
const sd = $getWorkflowStaticData('global');
const candidates = sd.candidates || {};
const existing = Object.values(candidates[site_id] || {}).map(c => typeof c === 'object' ? (c.topic || c.title || '') : String(c)).filter(Boolean);

const siteProfiles = {
  sinabarimd: 'sinabarimd.com — canonical identity hub for Dr. Sina Bari, MD. Topics: bio, work, media, selected writing, entity consolidation. NOT a blog — only high-signal content.',
  sinabari_net: 'sinabari.net — healthcare AI authority blog. Topics: 75% healthcare AI + 25% broader health tech (medtech, robotics, digital health, precision medicine). FORBIDDEN: plastic surgery, generic AI.',
  sinabariplasticsurgery: 'sinabariplasticsurgery.com — plastic surgery specialty. Topics: aesthetics, aging, rejuvenation, surgery, patient education. FORBIDDEN: healthcare AI, enterprise tech.',
  drsinabari: 'drsinabari.com — long-form editorial. Topics: medicine & technology, physician identity, clinical ethics, healthcare policy, medical humanities. Minimum 1500 words. FORBIDDEN: clinic promotion, plastic surgery, generic AI.'
};

const contentTypes = {
  standard: '800-1000 word article',
  short_form: '400-600 word focused piece',
  longform: '1500-2000 word in-depth editorial'
};

const existingList = existing.length ? '\nAlready suggested (DO NOT repeat these):\n' + existing.map(t => '- ' + t).join('\n') : '';
const seedContext = seed_text ? `\n\nThe operator has a starting idea or direction: "${seed_text}"\nUse this as a seed -- riff on it, expand it, find related angles. All 3 suggestions should be inspired by or connected to this seed idea.` : '';

const prompt = `You are a content strategist for Dr. Sina Bari, MD — a Stanford-trained surgeon and healthcare AI entrepreneur based in Los Angeles/Oakland.

Site profile: ${siteProfiles[site_id] || siteProfiles.sinabarimd}
Content format: ${contentTypes[content_type] || contentTypes.standard}
${existingList}

Suggest 3 fresh, specific topic ideas that would:
1. Strengthen Dr. Bari's authority in this domain
2. Target search queries real people are asking
3. Differentiate from generic AI-written content with a clinical/insider perspective

For each, provide:
- topic: A specific, compelling title (not generic)
- rationale: Why this topic works for SEO + authority (1 sentence)
- angle: The unique perspective Dr. Bari brings (1 sentence)

${seedContext}\n\nRespond as JSON array: [{"topic":"...","rationale":"...","angle":"..."},...]`;

const body = JSON.stringify({
  model: "anthropic/claude-sonnet-4-20250514",
  input: prompt,
  max_output_tokens: 1500
});

return [{ json: { openclaw_request_body: body, openclawAgentId: 'content-research' } }];

const response = $input.first().json;
let text = '';
if (response.output && Array.isArray(response.output)) {
  for (const item of response.output) {
    if (item.type === 'message' && item.content) {
      for (const c of item.content) {
        if (c.type === 'output_text') text += c.text;
      }
    }
  }
} else if (response.choices) {
  text = response.choices[0]?.message?.content || '';
}
if (!text) text = JSON.stringify(response);

// Extract JSON array from response
const match = text.match(/\[\s*\{[\s\S]*\}\s*\]/);
let suggestions = [];
if (match) {
  try { suggestions = JSON.parse(match[0]); } catch(e) {}
}

return [{ json: { suggestions } }];

const body = $json.body || $json;
const { site_id, topic, content_type = 'standard', attachment_b64, attachment_filename } = body;
const slug = (topic || 'untitled').toLowerCase().replace(/[^a-z0-9]+/g, '-').slice(0, 50);
const topic_id = site_id + '_' + new Date().toISOString().split('T')[0] + '_' + slug;

return [{ json: {
  site_id, topic, content_type,
  has_attachment: !!(attachment_b64 && attachment_filename),
  extract_body: (attachment_b64 && attachment_filename)
    ? JSON.stringify({ data: attachment_b64, filename: attachment_filename, topic_id })
    : null,
  topic_id,
} }];

const upstream = $('Prepare Attachment').first().json;
const extractResult = $json;
return [{ json: {
  site_id: upstream.site_id,
  topic: upstream.topic,
  content_type: upstream.content_type,
  attachment_text: extractResult.text || null,
  attachment_chars: extractResult.chars || 0,
} }];

// Queue gate: ensures only one deep research runs at a time
const staticData = $getWorkflowStaticData('global');
const body = $json.body || $json;
const { site_id, selected_topic, content_type = 'standard', additional_direction = '', skip_this_week = false } = body;

if (!site_id || !selected_topic) {
  throw new Error('Required: site_id and selected_topic');
}

// Initialize queue structures
if (!staticData.research_lock) staticData.research_lock = null;
if (!staticData.pending_research) staticData.pending_research = [];

const request = { site_id, selected_topic, content_type, additional_direction, skip_this_week, queued_at: new Date().toISOString() };

// Check if research is currently running (lock expires after 5 minutes as safety valve)
const lockAge = staticData.research_lock ? (Date.now() - new Date(staticData.research_lock).getTime()) : Infinity;
const isLocked = staticData.research_lock && lockAge < 300000; // 5 min timeout

if (isLocked) {
  // Queue this request and return immediately
  staticData.pending_research.push(request);
  return [{ json: { queued: true, position: staticData.pending_research.length, site_id, selected_topic, message: `Research queued (position ${staticData.pending_research.length}). Will run automatically after current research completes.` } }];
}

// Acquire lock and proceed
staticData.research_lock = new Date().toISOString();

return [{ json: { queued: false, proceed: true, ...request } }];

// Return queue position to dashboard
return [{ json: { 
  status: 'queued',
  position: $json.position,
  site_id: $json.site_id,
  selected_topic: $json.selected_topic,
  message: $json.message,
} }];

// Release lock and trigger next queued item
const staticData = $getWorkflowStaticData('global');

// Release lock
staticData.research_lock = null;

// Check if there are queued items
if (staticData.pending_research && staticData.pending_research.length > 0) {
  const next = staticData.pending_research.shift();

  // Fire the next research via webhook (self-trigger)
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://n8n.sinabarimd.com/webhook/research-deep',
      headers: { 'Content-Type': 'application/json' },
      body: next,
      json: true,
      timeout: 5000,
    });
  } catch(e) {
    // Timeout expected — the webhook fires async
  }

  return [{ json: { drained: true, next_site: next.site_id, next_topic: next.selected_topic } }];
}

return [{ json: { drained: false, queue_empty: true } }];

// Release lock and trigger next queued item (callback path)
const staticData = $getWorkflowStaticData('global');

// Release lock
staticData.research_lock = null;

// Check if there are queued items
if (staticData.pending_research && staticData.pending_research.length > 0) {
  const next = staticData.pending_research.shift();

  try {
    await this.helpers.httpRequest({
      method: 'POST',
